import React from 'react';
import './home.css';
import './assets/logo.png';

function Home() {
  return (
    <div className="home">
      <div className="logo-container">
        <img src="./assets/logo.png" alt="Logo" className="logo" />
      </div>
      <div className="content">
        <h1>Home</h1>
      </div>
    </div>
  );
}

export default Home;
